class Demo {
public:
    Demo() { std::cout << "Default\n"; }
    Demo(const Demo&) { std::cout << "Copy ctor\n"; }
    Demo& operator=(const Demo&) {
        std::cout << "Copy assign\n";
        return *this;
    }
};

void func(Demo d) {}  // Pass by value

Demo getDemo() {
    Demo d;
    return d;  // May use copy or move
}

int main() {
    Demo a;              // Default
    Demo b = a;          // Copy ctor (initialization)
    Demo c(a);           // Copy ctor (initialization)
    Demo d;              // Default
    d = a;               // Copy assign (reassignment)

    func(a);             // Copy ctor (pass by value)
    Demo e = getDemo();  // May elide or copy ctor
}

class String {
    char* data;
    size_t len;
public:
    // Copy constructor
    String(const String& other) 
        : data(new char[other.len + 1]), len(other.len) {
        std::strcpy(data, other.data);
    }

    // Copy assignment - self-assignment safe
    String& operator=(const String& other) {
        if (this != &other) {  // Self-assignment check
            char* newData = new char[other.len + 1];
            std::strcpy(newData, other.data);

            delete[] data;  // Clean up old
            data = newData; // Assign new
            len = other.len;
        }
        return *this;
    }

    ~String() { delete[] data; }
};

int main() {
    String s1("hello");
    String s2 = s1;  // Copy ctor
    s1 = s1;         // Self-assignment - safe
    s2 = s1;         // Normal assignment
}

class Buffer {
    int* data;
    size_t size;
public:
    Buffer(size_t n) : data(new int[n]), size(n) {}

    ~Buffer() { delete[] data; }

    // Copy constructor
    Buffer(const Buffer& other)
        : data(new int[other.size]), size(other.size) {
        std::copy(other.data, other.data + size, data);
    }

    // Copy assignment via copy-and-swap
    Buffer& operator=(Buffer other) {  // Pass by value!
        swap(*this, other);
        return *this;
    }

    friend void swap(Buffer& a, Buffer& b) noexcept {
        using std::swap;
        swap(a.data, b.data);
        swap(a.size, b.size);
    }
};

int main() {
    Buffer b1(100);
    Buffer b2(50);
    b1 = b2;  // Copy-and-swap: exception-safe, self-assignment safe
}

// BROKEN: Only destructor defined
class Broken {
    int* data;
public:
    Broken(int val) : data(new int(val)) {}
    ~Broken() { delete data; }
    // Missing: copy constructor and copy assignment
};

int main() {
    Broken a(42);
    Broken b = a;  // Shallow copy - both point to same data
    // When a and b destruct: DOUBLE DELETE - crash!
}

class Buffer {
    int* data;
    size_t size;
public:
    // Constructor
    Buffer(size_t n) : data(new int[n]), size(n) {}

    // Destructor
    ~Buffer() { delete[] data; }

    // Copy constructor - deep copy
    Buffer(const Buffer& other)
        : data(new int[other.size]), size(other.size) {
        std::copy(other.data, other.data + size, data);
    }

    // Copy assignment
    Buffer& operator=(const Buffer& other) {
        if (this != &other) {
            int* newData = new int[other.size];
            std::copy(other.data, other.data + other.size, newData);
            delete[] data;
            data = newData;
            size = other.size;
        }
        return *this;
    }

    // Move constructor - steal resources
    Buffer(Buffer&& other) noexcept
        : data(other.data), size(other.size) {
        other.data = nullptr;
        other.size = 0;
    }

    // Move assignment
    Buffer& operator=(Buffer&& other) noexcept {
        if (this != &other) {
            delete[] data;
            data = other.data;
            size = other.size;
            other.data = nullptr;
            other.size = 0;
        }
        return *this;
    }
};

// GOOD: Rule of 0 - no special members needed
class ModernBuffer {
    std::vector<int> data;  // Manages memory itself
public:
    ModernBuffer(size_t n) : data(n) {}

    // No destructor needed
    // No copy/move operations needed
    // Compiler-generated versions work perfectly

    size_t size() const { return data.size(); }
    int& operator[](size_t i) { return data[i]; }
};

int main() {
    ModernBuffer a(100);
    ModernBuffer b = a;          // Copy works
    ModernBuffer c = std::move(a);  // Move works
    // All cleanup automatic
}

class MoveOnly {
    std::unique_ptr<int> data;
public:
    // Allow default construction and move
    MoveOnly() = default;
    MoveOnly(MoveOnly&&) = default;
    MoveOnly& operator=(MoveOnly&&) = default;

    // Delete copy operations
    MoveOnly(const MoveOnly&) = delete;
    MoveOnly& operator=(const MoveOnly&) = delete;

    // Virtual destructor for polymorphic use
    virtual ~MoveOnly() = default;
};

int main() {
    MoveOnly a;
    // MoveOnly b = a;  // ERROR - copy deleted
    MoveOnly c = std::move(a);  // OK - move allowed
}

// WITHOUT virtual destructor - WRONG
class Base {
public:
    ~Base() { std::cout << "~Base\n"; }
};

class Derived : public Base {
    int* data;
public:
    Derived() : data(new int[100]) {}
    ~Derived() {
        delete[] data;
        std::cout << "~Derived\n";
    }
};

int main() {
    Base* ptr = new Derived();
    delete ptr;  // UB: Only ~Base called, memory leak!
    // Output: ~Base (missing ~Derived!)
}

// CORRECT version
class BaseFixed {
public:
    virtual ~BaseFixed() { std::cout << "~Base\n"; }
};

class DerivedFixed : public BaseFixed {
    int* data;
public:
    DerivedFixed() : data(new int[100]) {}
    ~DerivedFixed() override {
        delete[] data;
        std::cout << "~Derived\n";
    }
};

int main() {
    BaseFixed* ptr = new DerivedFixed();
    delete ptr;  // Correct: Both destructors called
    // Output:
    // ~Derived
    // ~Base
}

class Animal {
public:
    virtual void speak() const { std::cout << "Animal\n"; }
    virtual ~Animal() = default;
};

class Dog : public Animal {
    std::string name;
public:
    Dog(const std::string& n) : name(n) {}
    void speak() const override {
        std::cout << "Dog " << name << " barks\n";
    }
};

// WRONG: Pass by value causes slicing
void makeSpeak_BAD(Animal animal) {
    animal.speak();  // Always calls Animal::speak
}

// CORRECT: Pass by reference
void makeSpeak_GOOD(const Animal& animal) {
    animal.speak();  // Correct polymorphic call
}

int main() {
    Dog dog("Rex");

    makeSpeak_BAD(dog);   // Slicing: prints "Animal"
    makeSpeak_GOOD(dog);  // Correct: prints "Dog Rex barks"

    // Direct slicing
    Animal a = dog;  // Slicing occurs
    a.speak();       // Prints "Animal"
}

class Base {
protected:
    // Prevent slicing by deleting copy operations
    Base() = default;
    ~Base() = default;
    Base(const Base&) = delete;
    Base& operator=(const Base&) = delete;
public:
    virtual void func() = 0;
};

class Derived : public Base {
public:
    void func() override { std::cout << "Derived\n"; }
};

void process(Base obj) {}  // Would cause slicing

int main() {
    Derived d;
    // process(d);  // ERROR - copy deleted

    // Must use reference or pointer
    Base& ref = d;  // OK
    Base* ptr = &d; // OK
}

class Shape {
public:
    virtual void draw() const = 0;
    virtual ~Shape() = default;
};

class Circle : public Shape {
    int radius;
public:
    Circle(int r) : radius(r) {}
    void draw() const override {
        std::cout << "Circle radius " << radius << "\n";
    }
};

// WRONG: Slicing in container
void wrong_approach() {
    std::vector<Shape> shapes;  // ERROR: can't store abstract
    // Even if Shape was concrete:
    // shapes.push_back(Circle(5));  // Slicing!
}

// CORRECT: Use pointers
void correct_approach() {
    std::vector<std::unique_ptr<Shape>> shapes;
    shapes.push_back(std::make_unique<Circle>(5));

    for (const auto& shape : shapes) {
        shape->draw();  // Correct polymorphism
    }
}

